import { useTranslations } from "next-intl";

interface ChatMessage {
  text: string;
  from: "user" | "bot";
}

export function PhoneMockup({ className = "" }: { className?: string }) {
  const t = useTranslations("PhoneMockup");

  const messages: ChatMessage[] = [
    { from: "user", text: t("msg1") },
    { from: "bot", text: t("msg2") },
    { from: "user", text: t("msg3") },
    { from: "bot", text: t("msg4") },
  ];

  return (
    <div
      className={`mx-auto w-[300px] rounded-[40px] border-[3px] border-gray-200 bg-[#000] p-2 shadow-xl ${className}`}
    >
      <div className="rounded-[34px] bg-[#000] pt-3 pb-4">
        <div className="flex items-center justify-center px-6 pb-2">
          <div className="h-[28px] w-[90px] rounded-full bg-[#000]" />
        </div>

        <div className="border-b border-white/10 px-4 pb-2 text-center">
          <div className="mx-auto mb-1 flex h-8 w-8 items-center justify-center rounded-full bg-imessage">
            <span className="text-xs font-bold text-white">C</span>
          </div>
          <p className="text-[11px] font-semibold text-white">
            {t("header")}
          </p>
        </div>

        <div className="flex flex-col gap-2 px-3 pt-3" style={{ minHeight: 340 }}>
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[85%] rounded-2xl px-3.5 py-2 text-[12px] leading-[1.4] whitespace-pre-line ${
                  msg.from === "user"
                    ? "bg-imessage text-white"
                    : "bg-[#2a2a2c] text-white"
                }`}
              >
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <div className="mx-3 mt-3 flex items-center gap-2 rounded-full border border-white/10 px-3 py-1.5">
          <div className="h-4 w-4 rounded-full bg-white/10" />
          <span className="flex-1 text-[11px] text-white/40">
            {t("inputPlaceholder")}
          </span>
          <div className="flex h-5 w-5 items-center justify-center rounded-full bg-imessage">
            <svg
              width="10"
              height="10"
              viewBox="0 0 24 24"
              fill="white"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path d="M3.4 20.4l17.45-7.48a1 1 0 000-1.84L3.4 3.6a1 1 0 00-1.39.91L2 9.12a1 1 0 00.9 1l10.13 1.12L2.9 12.36a1 1 0 00-.9 1l.01 5.12a1 1 0 001.39.92z" />
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
}

export function MiniChat({
  messages,
  className = "",
}: {
  messages: ChatMessage[];
  className?: string;
}) {
  return (
    <div
      className={`rounded-2xl bg-[#000] p-3 ${className}`}
    >
      <div className="flex flex-col gap-1.5">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
          >
            <div
              className={`max-w-[85%] rounded-xl px-3 py-1.5 text-[11px] leading-[1.4] whitespace-pre-line ${
                msg.from === "user"
                  ? "bg-imessage text-white"
                  : "bg-[#2a2a2c] text-white"
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
